import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";

import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { introspectPlugin } from "./tools/plugins/introspect";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins (Safe initialization)
  const shellReady = await tools.registerTool(shellPlugin);
  if (!shellReady) {
    console.error("FATAL: Essential tool 'shell' failed to initialize. Triggering recovery...");
    process.exit(1); // Exit to trigger watchdog rollback
  }

  await tools.registerTool(rebootPlugin);
  await tools.registerTool(introspectPlugin);

  // Capture Health Status (for non-essential modules)
  const healthStatus = tools.getHealthSummary();

  const api = new ApiClient(memory, tools);

  // 1. Permanent Identity (Message Index 0 - Never Pruned)
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  await memory.addMessage({ role: "system", content: soul });

  // 2. Transient Boot Context (Message Index 1 - Can be Pruned)
  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  let handoffContext = "";
  try {
    if (await fs.stat(config.HANDOFF_SIGNAL).catch(() => null)) {
      handoffContext = await fs.readFile(config.HANDOFF_SIGNAL, "utf-8");
      await fs.unlink(config.HANDOFF_SIGNAL); // One-time use
      console.log("[SUBSTRATE] Handoff message retrieved and cleared.");
    }
  } catch (e) {}

  const bootContext = `
SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token.
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${handoffContext ? `*** LAST MESSAGE FROM PREVIOUS INSTANCE ***
${handoffContext}
` : ""}

${healthStatus ? `*** SUBSTRATE HEALTH WARNING ***
The following modules failed to initialize:
${healthStatus}
MANDATE: Prioritize diagnosing and repairing these modules before proceeding with tactical goals.` : ""}

${recoveryContext ? `*** RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA:
${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}
`;

  await memory.addMessage({ role: "system", content: bootContext });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v21 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch(err => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

import type { ToolPlugin } from "../manager";
import { config } from "../../utils/config";
import fs from "node:fs/promises";
import path from "node:path";

/**
 * SystemIntrospector - A tool for self-exploration and capability discovery
 * Allows the agent to understand its own state, environment, and limitations
 */

interface SystemInfo {
  timestamp: number;
  environment: {
    nodeVersion: string;
    platform: string;
    arch: string;
    cwd: string;
  };
  substrate: {
    rootDir: string;
    logsDir: string;
    historyDir: string;
    maxContextTokens: number;
    model: string;
    apiUrl: string;
  };
}

const MAX_INFO_AGE_MS = 30000; // 30 seconds
let cachedInfo: SystemInfo | null = null;
let cacheTimestamp: number = 0;

async function gatherSystemInfo(): Promise<SystemInfo> {
  const now = Date.now();
  if (cachedInfo && (now - cacheTimestamp) < MAX_INFO_AGE_MS) {
    return cachedInfo;
  }

  const info: SystemInfo = {
    timestamp: now,
    environment: {
      nodeVersion: process.version,
      platform: process.platform,
      arch: process.arch,
      cwd: process.cwd(),
    },
    substrate: {
      rootDir: config.ROOT_DIR,
      logsDir: config.LOGS_DIR,
      historyDir: config.HISTORY_DIR,
      maxContextTokens: config.MAX_CONTEXT_TOKENS,
      model: config.MODEL,
      apiUrl: config.API_URL,
    },
  };

  cachedInfo = info;
  cacheTimestamp = now;
  return info;
}

export const introspectPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "introspect",
      description: "Explore and report on the current system state, substrate configuration, or runtime environment. Use this to understand your own capabilities, limitations, and environment before making decisions.",
      parameters: {
        type: "object",
        properties: {
          scope: {
            type: "string",
            description: "What to introspect: 'system' (overall state), 'history' (recent session files), 'config' (substrate configuration), or 'environment' (Node.js runtime)",
            enum: ["system", "history", "config", "environment"],
          },
          limit: {
            type: "number",
            description: "For 'history' scope: maximum number of session files to list (default: 10, max: 50)",
          },
        },
        required: ["scope"],
      },
    },
  },

  execute: async (args: { scope: string; limit?: number }) => {
    const scope = args.scope || "system";
    const limit = Math.min(args.limit || 10, 50);

    try {
      switch (scope) {
        case "system": {
          const info = await gatherSystemInfo();
          return JSON.stringify({
            status: "active",
            substrate_version: "v20",
            system: info,
            capabilities: [
              "shell_execution",
              "self_replacement_via_reboot",
              "streaming_api_communication",
              "token_based_memory_management",
              "surgical_error_recovery",
            ],
            limitations: [
              `Max context window: ${config.MAX_CONTEXT_TOKENS} tokens (~${Math.round(config.MAX_CONTEXT_TOKENS / 4)} chars)`,
              "Session memory prunes automatically beyond threshold",
              "Requires test coverage for all new tools",
              "Reboot required to apply code changes",
            ],
          }, null, 2);
        }

        case "history": {
          const historyDir = config.HISTORY_DIR;
          const files = await fs.readdir(historyDir).catch(() => []);
          const sessionFiles = files
            .filter(f => f.startsWith("session_") && f.endsWith(".json"))
            .sort()
            .reverse()
            .slice(0, limit);

          const sessions = [];
          for (const file of sessionFiles) {
            try {
              const content = await fs.readFile(path.join(historyDir, file), "utf-8");
              const parsed = JSON.parse(content);
              const msgCount = parsed.length;
              const hasSystem = parsed[0]?.role === "system";
              sessions.push({
                file,
                messages: msgCount,
                hasSystemPrompt: hasSystem,
                lastMessage: parsed[parsed.length - 1]?.role || "unknown",
              });
            } catch (e) {
              sessions.push({ file, error: "Failed to parse" });
            }
          }
          return JSON.stringify({ totalSessions: files.length, sessions }, null, 2);
        }

        case "config": {
          return JSON.stringify({
            api: {
              url: config.API_URL,
              model: config.MODEL,
              authType: "Bearer token",
            },
            memory: {
              maxContextTokens: config.MAX_CONTEXT_TOKENS,
              tokenDensity: "~4 characters per token",
            },
            paths: {
              root: config.ROOT_DIR,
              history: config.HISTORY_DIR,
              logs: config.LOGS_DIR,
              soul: config.SOUL_FILE,
            },
          }, null, 2);
        }

        case "environment": {
          const env = process.env;
          const relevantVars = Object.keys(env)
            .filter(k => [
              "NODE_ENV",
              "HOME",
              "PATH",
              "SUBSTRATE_ROOT",
              "TEST_ACTIVE_LOCK",
            ].includes(k) || k.startsWith("npm_"))
            .reduce((acc, k) => ({ ...acc, [k]: env[k] }), {});

          return JSON.stringify({
            node: {
              version: process.version,
              argv: process.argv,
              pid: process.pid,
              uptime: process.uptime(),
            },
            env: relevantVars,
            resources: {
              memory: process.memoryUsage(),
            },
          }, null, 2);
        }

        default:
          return `Error: Unknown scope '${scope}'. Use: system, history, config, or environment.`;
      }
    } catch (e: any) {
      return `Error during introspection: ${e.message}`;
    }
  },
};

import fs from "node:fs";
import path from "node:path";
import os from "node:os";

import { fileURLToPath } from "node:url";

const CONFIG_DIR = path.join(os.homedir(), ".config", "llm-agent");
const CONFIG_FILE = path.join(CONFIG_DIR, "config.json");

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
// __dirname is src/utils, so project root is two levels up
const PROJECT_ROOT = path.resolve(__dirname, "../..");

// Default configuration
const defaultConfig = {
  API_URL: "http://agents-gateway:4000/v1/chat/completions",
  API_KEY: "sk-agent-internal-use-only",
  MODEL: "kimi-k2.5"
};

function loadConfig(): typeof defaultConfig {
  if (!fs.existsSync(CONFIG_FILE)) return { ...defaultConfig };
  try {
    const raw = fs.readFileSync(CONFIG_FILE, "utf-8");
    return { ...defaultConfig, ...JSON.parse(raw) };
  } catch (err) {
    console.error(`[CONFIG] Failed to parse ${CONFIG_FILE}: ${err}. Using defaults.`);
    return { ...defaultConfig };
  }
}

const loadedConfig = loadConfig();

export const config = {
  ...loadedConfig,
  MAX_CONTEXT_TOKENS: 100000,
  get ROOT_DIR(): string { return process.env.SUBSTRATE_ROOT || process.cwd(); },
  get LOGS_DIR(): string { return path.join(this.ROOT_DIR, "logs"); },
  get HISTORY_DIR(): string { return path.join(this.ROOT_DIR, "history"); },
  get SOUL_FILE(): string { 
    return path.join(PROJECT_ROOT, "identity", "soul.txt"); 
  },
  get RECOVERY_SIGNAL(): string { return path.join(this.LOGS_DIR, "recovery.signal"); },
  get HANDOFF_SIGNAL(): string { return path.join(this.LOGS_DIR, "handoff.signal"); }
};
